// Get raw text from OpenAI output
let raw = $input.first().json.output[0].content[0].text
// If the JSON is inside markdown ```json ... ``` remove the backticks
if (typeof raw === "string") {
  raw = raw.replace(/```json/gi, "").replace(/```/g, "").trim();
}

// Now parse the cleaned JSON string
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error("Failed to parse GPT JSON: " + e.message + "\nRaw: " + raw);
}

// Output parsed JSON so n8n can access real fields
return [{ json: parsed }];

// Function node: convert JSON fileData → binary

return items.map(item => {
  const file = item.json.body.files[0];

  // Attach binary data in the format n8n expects
  item.binary = {
    data: {
      // We already have base64 from the webhook, so just pass it through
      data: file.fileData,
      mimeType: file.fileType,      // "application/pdf"
      fileName: file.fileName,      // "1363_001.pdf"
    },
  };

  // Keep any metadata you want in JSON
  item.json = {
    fileName: file.fileName,
    mimeType: file.fileType,
    source: item.json.body.source,
    timestamp: item.json.body.timestamp,
  };

  return item;
});

